import type {
  Holiday,
  Scale,
  ShiftSwap,
  TeamMember,
  TimeOff,
} from "@/contexts/ScheduleContext";
import { getMonthSchedule, isHoliday, isWorkingDay } from "@/lib/scheduleCalculator";

type ExportPdfOptions = {
  year: number;
  month: number;
  teamMembers: TeamMember[];
  scales: Scale[];
  timeOffs: TimeOff[];
  holidays: Holiday[];
  shiftSwaps: ShiftSwap[];
  isPersonOnTimeOff?: (personName: string, dateStr: string) => boolean;
};

const weekdayLabels = [
  "Domingo",
  "Segunda",
  "Ter\u00e7a",
  "Quarta",
  "Quinta",
  "Sexta",
  "S\u00e1bado",
];

const AUTO_FRIDAY_SWAP_REASON = "troca automatica de sexta";

function normalizeText(value: string): string {
  return value
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase()
    .trim();
}

function isAutoFridaySwap(reason?: string): boolean {
  if (!reason) return false;
  return normalizeText(reason) === AUTO_FRIDAY_SWAP_REASON;
}

const TJSP_LOGO_PNG = "data:image/jpeg;base64,";

function dateToYMD(date: Date): string {
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, "0");
  const day = String(date.getDate()).padStart(2, "0");
  return `${year}-${month}-${day}`;
}

// helpers for PDF export

export async function exportCalendarToPdf({
  year,
  month,
  teamMembers,
  scales,
  timeOffs,
  holidays,
  shiftSwaps,
  isPersonOnTimeOff,
}: ExportPdfOptions) {
  const { jsPDF } = await import("jspdf");

  const daysInMonth = new Date(year, month + 1, 0).getDate();
  const holidayDates = holidays.map((holiday) => holiday.date);
  const monthSchedule = getMonthSchedule(
    year,
    month,
    teamMembers,
    scales,
    isPersonOnTimeOff,
    holidayDates,
    shiftSwaps
  );
  const scheduleByDate = new Map(
    monthSchedule.map((item) => [dateToYMD(item.date), item])
  );

  const rows: Array<{
    dayLabel: string;
    weekdayLabel: string;
    name: string;
    weekIndex: number;
    isNonWorking: boolean;
    isHoliday: boolean;
  }> = [];

  let weekIndex = -1;
  for (let day = 1; day <= daysInMonth; day += 1) {
    const date = new Date(year, month, day);
    const dayOfWeek = date.getDay();
    if (dayOfWeek === 0 || dayOfWeek === 6) continue;
    if (dayOfWeek === 1) weekIndex += 1;

    const dateStr = dateToYMD(date);
    const holiday = holidays.find((item) => item.date === dateStr);
    const workingDay = isWorkingDay(date, holidayDates);
    const holidayDay = isHoliday(date, holidayDates);
    const scheduleInfo = scheduleByDate.get(dateStr);

    let name = "";
    let isNonWorking = false;

    if (!workingDay) {
      isNonWorking = true;
      name = holidayDay
        ? `Sem expediente - ${holiday?.name ?? "Feriado"}`
        : "Sem expediente";
    } else if (!scheduleInfo) {
      name = "Sem escala";
    } else {
      const assigned = scheduleInfo.person ?? "";
      const marked = isAutoFridaySwap(scheduleInfo.swapReason)
        ? `${assigned} ***`
        : assigned;
      name = marked;
    }

    rows.push({
      dayLabel: String(day).padStart(2, "0"),
      weekdayLabel: weekdayLabels[dayOfWeek],
      name,
      weekIndex,
      isNonWorking,
      isHoliday: holidayDay,
    });
  }

  const pdf = new jsPDF({
    orientation: "portrait",
    unit: "mm",
    format: "a4",
  });

  const pageWidth = pdf.internal.pageSize.getWidth();
  const pageHeight = pdf.internal.pageSize.getHeight();

  const headerLines = [
    "PODER JUDICI\u00c1RIO DO ESTADO DE S\u00c3O PAULO",
    "SE\u00c7\u00c3O ADMINISTRATIVA DE DISTRIBUI\u00c7\u00c3O DE MANDADOS",
    "COMARCA DE HORTOL\u00c2NDIA - ESTADO DE S\u00c3O PAULO",
    "Rua Sebasti\u00e3o Cust\u00f3dio de Oliveira, 20 - Hortol\u00e2ndia-SP   CEP 13184-507",
    "E-mail: hortolandia@tjsp.jus.br",
  ];

  const headerStartY = 12;
  const headerLineHeight = 4;
  const crestWidth = 38;
  const crestHeight = (crestWidth * 127) / 299;
  const crestX = 14;
  const crestY = headerStartY - 3;

  try {
    pdf.addImage(TJSP_LOGO_PNG, "PNG", crestX, crestY, crestWidth, crestHeight);
  } catch {
    pdf.setFont("helvetica", "bold");
    pdf.setFontSize(7);
    pdf.text("TJSP", crestX + crestWidth / 2, crestY + crestHeight / 2 + 2, {
      align: "center",
    });
  }

  headerLines.forEach((line, index) => {
    pdf.setFont("helvetica", index === 0 ? "bold" : "normal");
    pdf.setFontSize(index === 0 ? 10 : 8);
    pdf.text(line, pageWidth / 2, headerStartY + index * headerLineHeight, {
      align: "center",
    });
  });

  const headerBottom = headerStartY + headerLines.length * headerLineHeight + 2;
  pdf.setLineWidth(0.3);
  pdf.line(14, headerBottom, pageWidth - 14, headerBottom);

  pdf.setFont("helvetica", "bold");
  pdf.setFontSize(11);
  pdf.text("ESCALA DE PLANT\u00c3O DOS OFICIAIS DE JUSTI\u00c7A", pageWidth / 2, headerBottom + 7, {
    align: "center",
  });

  const monthLabel = new Intl.DateTimeFormat("pt-BR", { month: "long" })
    .format(new Date(year, month, 1))
    .toUpperCase();
  pdf.setFontSize(14);
  pdf.text(`${monthLabel}/${year}`, pageWidth / 2, headerBottom + 15, {
    align: "center",
  });

  const tableWidth = 120;
  const tableX = (pageWidth - tableWidth) / 2;
  const colWidths = [14, 32, tableWidth - 46];
  const rowHeight = 7;
  let cursorY = headerBottom + 22;

  const drawRow = (
    rowIndex: number,
    dayLabel: string,
    weekdayLabel: string,
    name: string,
    shaded: boolean,
    muted: boolean,
    holiday: boolean
  ) => {
    if (cursorY + rowHeight > pageHeight - 15) {
      pdf.addPage();
      cursorY = 20;
    }

    if (holiday) {
      pdf.setFillColor(217, 217, 217);
      pdf.rect(tableX, cursorY, tableWidth, rowHeight, "F");
    } else if (shaded) {
      pdf.setFillColor(153, 187, 226);
      pdf.rect(tableX, cursorY, tableWidth, rowHeight, "F");
    }

    pdf.setDrawColor(0);
    pdf.setLineWidth(0.2);
    pdf.rect(tableX, cursorY, colWidths[0], rowHeight);
    pdf.rect(tableX + colWidths[0], cursorY, colWidths[1], rowHeight);
    pdf.rect(tableX + colWidths[0] + colWidths[1], cursorY, colWidths[2], rowHeight);

    pdf.setFont("helvetica", holiday ? "bolditalic" : "normal");
    pdf.setFontSize(9);
    pdf.setTextColor(holiday ? 20 : muted ? 120 : 20);

    pdf.text(dayLabel, tableX + colWidths[0] / 2, cursorY + 4.6, {
      align: "center",
    });
    pdf.text(weekdayLabel, tableX + colWidths[0] + colWidths[1] / 2, cursorY + 4.6, {
      align: "center",
    });
    pdf.text(name, tableX + colWidths[0] + colWidths[1] + 2, cursorY + 4.6);

    cursorY += rowHeight;
  };

  rows.forEach((row, index) => {
    const shaded = row.weekIndex % 2 === 1;
    drawRow(
      index,
      row.dayLabel,
      row.weekdayLabel,
      row.name,
      shaded,
      row.isNonWorking,
      row.isHoliday
    );
  });

  pdf.setTextColor(20);

  // Sem observacoes no rodape

  const now = new Date();
  const stamp = [
    now.getFullYear(),
    String(now.getMonth() + 1).padStart(2, "0"),
    String(now.getDate()).padStart(2, "0"),
  ].join("-");

  pdf.save(`escala-plantao-${stamp}.pdf`);
}
